%[text] # Analysis
%[text] Plots for static and dynamic force, current, and audio data
clear; clc; close all hidden;
%%
%[text] ## Configuration
AXIS = 3; %[control:dropdown:7ac0]{"position":[8,9]}
STATIC_FOLDER = "C:\Users\awang127\Documents\MATLAB\Linear-Traverse\Data\2025_07_15_STAT"; %[control:filebrowser:879a]{"position":[17,90]}
DYNAMIC_FOLDER = "C:\Users\awang127\Documents\MATLAB\Linear-Traverse\Data\2025_07_15_DYN"; %[control:filebrowser:0186]{"position":[18,90]}
OUT_FOLDER = "C:\Users\awang127\Downloads"; %[control:filebrowser:2fa5]{"position":[14,43]}
CONFIGURATION = "stacked"; %[control:dropdown:8fc3]{"position":[17,26]}
MAX = 1; %[control:slider:32c3]{"position":[7,8]}
BASE_POINTS = 500; %[control:slider:40cd]{"position":[15,18]}
ERRORBAR = true; %[control:checkbox:3bbe]{"position":[12,16]}
CF_VOLTAGE = 4;
%%
name = Config.NAMES(AXIS);
conv = dictionary(Config.NAMES, ["F_y" "F_x" "F_z" "M_y" "M_x" "M_z"]);
disp_name = conv(name);

out_folder = fullfile(OUT_FOLDER, strjoin(["analysis", CONFIGURATION, disp_name], "-"));

if ~exist(out_folder, "dir")
    mkdir(out_folder);
end
%%
%[text] ## 2D Test
%[text] Plot chosen axis versus distance with color to represent speed
if AXIS <= 3
    DENOMINATOR = Config.W * MAX;
    Process.format_plot("", "Separation, $\Delta z/l$", "Force, $\bar{" + disp_name + "}/W$"); %[output:3cf5a3fc]
else
    DENOMINATOR = Config.W * Config.L * MAX;
    Process.format_plot("", "Separation, $\Delta z/l$", "Moment, $\bar{" + disp_name + "}/(Wl)$");
end

axis("square"); %[output:3cf5a3fc]
xlim([0 8]); %[output:3cf5a3fc]
set(gcf, 'Renderer', 'painters', 'Position', [100 100 1000 750]); %[output:3cf5a3fc]

p = gca();
p.OuterPosition(3) = 0.95; %[output:3cf5a3fc]

%% Dynamic
folder_path = fullfile(DYNAMIC_FOLDER, 'processed_data');
items = dir(fullfile(folder_path, '*.mat'));
filenames = string({items.name});

a = colorbar; %[output:3cf5a3fc]
a.Label.Rotation = 270; %[output:3cf5a3fc]
a.Label.Interpreter = "latex"; %[output:3cf5a3fc]
a.Label.String = 'Velocity, $(\Delta\dot{z}/U_i)$'; %[output:3cf5a3fc]
a.Label.FontSize = 18; %[output:3cf5a3fc]
colormap(slanCM('coolwarm')); %[output:38548afd] %[output:3cf5a3fc]

% Set colormap limits
scatter([9 9], [0 0], [1 1], 2 * pi * 1 * 0.09 / Config.U_i * [1 -1]); %[output:3cf5a3fc]

% Preallocate table
params = arrayfun(@(f) sscanf(f, 'CF%f_SD%f_F%f_A%f.mat'), filenames, 'UniformOutput', false);
AS = cellfun(@(v) v(4), params);
rows = sum(BASE_POINTS * AS / 5);

dynamic = table( ...
    strings(rows, 1), ... % case
    zeros(rows, 1), ...   % distance
    zeros(rows, 1), ...   % moment
    zeros(rows, 1), ...   % velocity
    'VariableNames', {'case', 'distance', 'moment', 'velocity'} ...
);
i = 1;

for filename = filenames

    parameters = num2cell(sscanf(filename, 'CF%f_SD%f_F%f_A%f.mat'));
    [CF, SD, F, A] = deal(parameters{:});
    SD = SD / 100;
    A = A / 100;

    if A == 0
        continue
    end

    load(fullfile(folder_path, filename), 'time', 'forces', 'pos_encoder');

    offset = (pos_encoder(end) - pos_encoder(1)) / (length(pos_encoder) - 1) * (0:length(pos_encoder) - 1);
    pos_encoder = pos_encoder - pos_encoder(1) - offset';

    position_fit = fit_sinusoid(time, pos_encoder, A, F);
    distance = SD + position_fit.A + position_fit(time);
    velocity = differentiate(position_fit, time);

    forces_smoothed = smooth(forces.Total(:, AXIS), length(forces.Total) / 10) / DENOMINATOR;

    idx = floor(linspace(1, length(distance), BASE_POINTS * A / 0.05));
    s = scatter(distance(idx) / (Config.L / 1000), forces_smoothed(idx), 3, velocity(idx) / Config.U_i, 'filled'); %[output:3cf5a3fc]
    s.MarkerFaceAlpha = 0.5;
    
    n = length(idx);
    dynamic.case(i:i+n-1) = repmat(filename, n, 1);
    dynamic.distance(i:i+n-1) = distance(idx) / (Config.L / 1000);
    dynamic.moment(i:i+n-1) = forces_smoothed(idx);
    dynamic.velocity(i:i+n-1) = velocity(idx) / Config.U_i;
    i = i + n;
end

%% Static

load(fullfile(STATIC_FOLDER, 'processed_data'), 'results');
SDS = results.(name).SD / (Config.L / 1000);
static = table2array(results.(name)(:, 2:end)) / DENOMINATOR;

if ERRORBAR == true
    % Plot results (error bars)
    errorbar(SDS, mean(static, 2), std(static, 0, 2), 'ko', 'LineWidth', 1.5); %[output:3cf5a3fc]
else
    % Plot results (data)
    plot(SDS, static, "kx", "MarkerSize", 8, "LineWidth", 1.5);
end

%% Save
print(gcf, fullfile(out_folder, "twodtest.svg"), "-dsvg"); %[output:3cf5a3fc]
savefig(gcf, fullfile(out_folder, "twodtest.fig"));

static = results.(Config.NAMES(AXIS));
save(fullfile(out_folder, "twodtest.mat"), 'static', 'dynamic');

function fitresult = fit_sinusoid(t, s, A, F)
    % Convert to column vectors
    t = t(:);
    s = s(:);

    % Define the sinusoidal fit type
    ft = fittype(@(A, C, t) A*sin(2*pi*F*t + C), 'independent', 't', 'coefficients', {'A', 'C'});

    % Fit the model to the data
    fitresult = fit(t, s, ft, 'StartPoint', [A, 0]);
end
%%
%[text] ## Crazyflie Power
figure; %[output:3e281d56]
Process.format_plot("", "Separation, $\Delta z/l$", "Power, W"); %[output:3e281d56]

axis("square");
xlim([0 8]);
ylim([5 10]);
set(gcf, 'Renderer', 'painters', 'Position', [100 100 1000 750]);

load(fullfile(STATIC_FOLDER, 'processed_data'), 'results');
SDS = results.(name).SD / (Config.L / 1000);
current = table2array(results.Current(:, 2:end));
power = current * CF_VOLTAGE;

if ERRORBAR == true
    % Plot results (error bars)
    errorbar(SDS, mean(power, 2), std(power, 0, 2), 'ko', 'LineWidth', 1.5); %[output:3e281d56]
else
    % Plot results (data)
    plot(SDS, power, "kx", "MarkerSize", 8, "LineWidth", 1.5);
end %[output:3e281d56]

%% Save
print(gcf, fullfile(out_folder, "power.svg"), "-dsvg");
savefig(gcf, fullfile(out_folder, "power.fig"));
%%
%[text] ## Peak Frequencies
figure %[output:7f083d93]
Process.format_plot("", "Separation, $\Delta z/l$", "Audio Peaks, Hz"); %[output:7f083d93]

axis("square");
xlim([0 8]);
set(gcf, 'Renderer', 'painters', 'Position', [100 100 1000 750]);

load(fullfile(STATIC_FOLDER, 'processed_data'), 'results');
SDS = results.(name).SD / (Config.L / 1000);
first = table2array(results.("First Peak")(:, 2:end));
second = table2array(results.("Second Peak")(:, 2:end));

scatter(SDS, median(first, 2), "filled", "DisplayName", "First Peak"); %[output:7f083d93]
scatter(SDS, median(second, 2), "filled", "DisplayName", "Second Peak"); %[output:7f083d93]
legend(); %[output:7f083d93]

%% Save
print(gcf, fullfile(out_folder, "frequency.svg"), "-dsvg");
savefig(gcf, fullfile(out_folder, "frequency.fig"));

